import{_ as a,o as e,c as l,a2 as n}from"./chunks/framework.Pywvta2k.js";const u=JSON.parse('{"title":"圆运动的古中医学","description":"","frontmatter":{},"headers":[],"relativePath":"tcm-data/05-近现代/01-圆运动的古中医学（彭子益-李可）.md","filePath":"tcm-data/05-近现代/01-圆运动的古中医学（彭子益-李可）.md","lastUpdated":1781084559000}'),s={name:"tcm-data/05-近现代/01-圆运动的古中医学（彭子益-李可）.md"};function o(r,t,i,g,d,h){return e(),l("div",null,[...t[0]||(t[0]=[n(`<h1 id="圆运动的古中医学" tabindex="-1">圆运动的古中医学 <a class="header-anchor" href="#圆运动的古中医学" aria-label="Permalink to &quot;圆运动的古中医学&quot;">​</a></h1><blockquote><p>彭子益（1871-1949年），云南人 李可（1930-2013年），山西灵石人 李可主校并鼎力推广的&quot;中医真正的正统传承&quot;</p></blockquote><hr><h2 id="一、基本信息" tabindex="-1">一、基本信息 <a class="header-anchor" href="#一、基本信息" aria-label="Permalink to &quot;一、基本信息&quot;">​</a></h2><h3 id="彭子益" tabindex="-1">彭子益 <a class="header-anchor" href="#彭子益" aria-label="Permalink to &quot;彭子益&quot;">​</a></h3><ul><li><strong>字号</strong>：字子益，号鉴湖老人</li><li><strong>籍贯</strong>：云南大理（与您同在大理！）</li><li><strong>生平</strong>：民国时期医学家，曾任云南中医学校校长</li><li><strong>著作</strong>：《圆运动的古中医学》（原名为《系统学》）</li><li><strong>学术命运</strong>：著作长期湮没，直到李可发现并整理出版</li></ul><h3 id="李可" tabindex="-1">李可 <a class="header-anchor" href="#李可" aria-label="Permalink to &quot;李可&quot;">​</a></h3><ul><li><strong>字号</strong>：名永福，字可</li><li><strong>籍贯</strong>：山西灵石</li><li><strong>生平</strong>：自学中医，因治愈危重病人声名鹊起</li><li><strong>代表作</strong>：《李可老中医急危重症疑难病经验专辑》</li><li><strong>学术地位</strong>：近代经方派的代表人物，&quot;<strong>破格救心</strong>&quot;</li></ul><h3 id="两部著作的关系" tabindex="-1">两部著作的关系 <a class="header-anchor" href="#两部著作的关系" aria-label="Permalink to &quot;两部著作的关系&quot;">​</a></h3><p>李可在上世纪90年代偶然发现彭子益的《圆运动的古中医学》遗稿，被其理论震撼，认为<strong>这是中医真正的正统传承</strong>。李可主校、整理并出版了该书，并称：</p><blockquote><p><strong>「彭子益先生是中医复兴之父，从此以后，中医亡不了！」</strong></p></blockquote><hr><h2 id="二、核心理论" tabindex="-1">二、核心理论 <a class="header-anchor" href="#二、核心理论" aria-label="Permalink to &quot;二、核心理论&quot;">​</a></h2><h3 id="_1-圆运动-——-对-一气周流-的极致发挥" tabindex="-1">1. 圆运动 —— 对&quot;一气周流&quot;的极致发挥 <a class="header-anchor" href="#_1-圆运动-——-对-一气周流-的极致发挥" aria-label="Permalink to &quot;1. 圆运动 —— 对&quot;一气周流&quot;的极致发挥&quot;">​</a></h3><p>彭子益认为，人体生理和宇宙一样，是一个<strong>圆运动</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>        夏（火）</span></span>
<span class="line"><span>           ↑</span></span>
<span class="line"><span>    春（木）←中气→秋（金）</span></span>
<span class="line"><span>           ↓</span></span>
<span class="line"><span>        冬（水）</span></span></code></pre></div><ul><li><strong>中气如轴，四维如轮</strong></li><li><strong>轴运轮行，轴滞轮停</strong></li><li>所有疾病都是圆运动的某一环节失常</li></ul><h3 id="_2-十二经圆运动" tabindex="-1">2. 十二经圆运动 <a class="header-anchor" href="#_2-十二经圆运动" aria-label="Permalink to &quot;2. 十二经圆运动&quot;">​</a></h3><p>彭子益从《内经》六气理论与《伤寒论》六经辨证出发，构建了<strong>十二经圆运动</strong>模型：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>                         太阳寒水（膀胱）</span></span>
<span class="line"><span>                              ↑</span></span>
<span class="line"><span>                手太阳（小肠） │</span></span>
<span class="line"><span>                              │</span></span>
<span class="line"><span>厥阴风木（肝）——少阴君火（心）——太阴湿土（脾）</span></span>
<span class="line"><span>       │                                  │</span></span>
<span class="line"><span>       │         足少阳胆（下降）          │</span></span>
<span class="line"><span>       └──────────────┬──────────────────┘</span></span>
<span class="line"><span>                      │</span></span>
<span class="line"><span>              阳明燥金（胃）——少阳相火（胆经下降入肾）</span></span>
<span class="line"><span>                      │</span></span>
<span class="line"><span>                      ↓</span></span>
<span class="line"><span>               少阴君火（肾）</span></span></code></pre></div><h3 id="_3-二十四节气圆运动" tabindex="-1">3. 二十四节气圆运动 <a class="header-anchor" href="#_3-二十四节气圆运动" aria-label="Permalink to &quot;3. 二十四节气圆运动&quot;">​</a></h3><p>彭子益将一年二十四节气对应人体的气机升降，认为人体的小圆运动与天地的大圆运动同步。<strong>节气前后是最容易生病的时候。</strong></p><h3 id="_4-本气自病" tabindex="-1">4. 本气自病 <a class="header-anchor" href="#_4-本气自病" aria-label="Permalink to &quot;4. 本气自病&quot;">​</a></h3><blockquote><p><strong>「凡病皆本气自病。本气者，人身之本有之气也。」</strong></p></blockquote><ul><li>疾病不是外邪&quot;入侵&quot;，而是<strong>人体自身圆运动失常</strong></li><li>治疗的根本是<strong>恢复自身的圆运动</strong></li><li><strong>这一思想是黄元御&quot;中气论&quot;的进一步发展</strong></li></ul><h3 id="_5-古方上篇-——-经方的圆运动解释" tabindex="-1">5. 古方上篇 —— 经方的圆运动解释 <a class="header-anchor" href="#_5-古方上篇-——-经方的圆运动解释" aria-label="Permalink to &quot;5. 古方上篇 —— 经方的圆运动解释&quot;">​</a></h3><p>彭子益对《伤寒论》《金匮要略》的经方做了全新的圆运动解释：</p><table tabindex="0"><thead><tr><th style="text-align:left;">经方</th><th style="text-align:left;">圆运动解释</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>桂枝汤</strong></td><td style="text-align:left;">木气疏泄太过（荣卫不和），桂枝升肝、芍药敛胆</td></tr><tr><td style="text-align:left;"><strong>麻黄汤</strong></td><td style="text-align:left;">木气被寒邪束缚，麻黄开表、桂枝升肝</td></tr><tr><td style="text-align:left;"><strong>小柴胡汤</strong></td><td style="text-align:left;">少阳相火不降，柴胡升肝转枢、黄芩降相火</td></tr><tr><td style="text-align:left;"><strong>四逆汤</strong></td><td style="text-align:left;">肾水寒、中气败，附子温肾水、干姜温中气</td></tr><tr><td style="text-align:left;"><strong>理中丸</strong></td><td style="text-align:left;">中气虚寒、圆运动轴心停止，参姜温中、苓术除湿</td></tr></tbody></table><hr><h2 id="三、李可的核心贡献" tabindex="-1">三、李可的核心贡献 <a class="header-anchor" href="#三、李可的核心贡献" aria-label="Permalink to &quot;三、李可的核心贡献&quot;">​</a></h2><h3 id="_1-破格救心汤-李可最著名的方剂" tabindex="-1">1. 破格救心汤（李可最著名的方剂） <a class="header-anchor" href="#_1-破格救心汤-李可最著名的方剂" aria-label="Permalink to &quot;1. 破格救心汤（李可最著名的方剂）&quot;">​</a></h3><p><strong>组成</strong>：附子30-100-200g、干姜60g、炙甘草60g、人参30g、山萸肉30-120g、龙骨30g、牡蛎30g、磁石30g</p><ul><li>用于<strong>心衰重症</strong>：心功能衰竭、休克</li><li>附子用量极大（200g以上），但配合炙甘草、山萸肉、龙骨、牡蛎，安全有效</li><li>被誉为&quot;中医ICU&quot;</li></ul><h3 id="_2-温氏奔豚汤" tabindex="-1">2. 温氏奔豚汤 <a class="header-anchor" href="#_2-温氏奔豚汤" aria-label="Permalink to &quot;2. 温氏奔豚汤&quot;">​</a></h3><p>李可从民间老中医温碧泉处所得，用于<strong>水寒土湿、相火不降</strong>证： 组成：附子30g、油桂10g、红参10g、沉香5g、砂仁10g、山药30g、茯苓30g、泽泻10g、怀牛膝10g、炙甘草10g</p><p><strong>普明师嫂的月经先期、上热下寒与此方思路高度吻合。</strong></p><h3 id="_3-重用附子的安全策略" tabindex="-1">3. 重用附子的安全策略 <a class="header-anchor" href="#_3-重用附子的安全策略" aria-label="Permalink to &quot;3. 重用附子的安全策略&quot;">​</a></h3><p>李可的附子用法：</p><ul><li>生附子 → 先煎2小时以上</li><li>制附子 → 先煎45-60分钟</li><li>配合大量炙甘草（30-60g）→ 解附子毒</li><li>配合山萸肉 → 养阴助心气，防附子辛燥太过</li></ul><hr><h2 id="四、代表方剂" tabindex="-1">四、代表方剂 <a class="header-anchor" href="#四、代表方剂" aria-label="Permalink to &quot;四、代表方剂&quot;">​</a></h2><h3 id="李可常用方" tabindex="-1">李可常用方 <a class="header-anchor" href="#李可常用方" aria-label="Permalink to &quot;李可常用方&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">方名</th><th style="text-align:left;">组成</th><th style="text-align:left;">主治</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>破格救心汤</strong></td><td style="text-align:left;">附子30-200g、干姜60g、炙甘草60g、人参30g、山萸肉30-120g、龙骨30g、牡蛎30g、磁石30g</td><td style="text-align:left;">心衰、休克</td></tr><tr><td style="text-align:left;"><strong>温氏奔豚汤</strong></td><td style="text-align:left;">附子、油桂、红参、沉香、砂仁、山药、茯苓、泽泻、牛膝、炙甘草</td><td style="text-align:left;">水寒土湿、相火不降</td></tr><tr><td style="text-align:left;"><strong>培元固本散</strong></td><td style="text-align:left;">人参、鹿茸、三七、琥珀、鹿角胶、紫河车等</td><td style="text-align:left;">慢病调养、预防复发</td></tr><tr><td style="text-align:left;"><strong>乌头汤</strong></td><td style="text-align:left;">制川乌30g、黄芪60g、麻黄15g、白芍30g、甘草30g、蜂蜜120g</td><td style="text-align:left;">类风湿、强脊炎</td></tr><tr><td style="text-align:left;"><strong>攻癌夺命汤</strong></td><td style="text-align:left;">附子、干姜、炙甘草、人参、五灵脂、桃仁、红花等</td><td style="text-align:left;">晚期肿瘤</td></tr></tbody></table><hr><h2 id="五、经典名言精选" tabindex="-1">五、经典名言精选 <a class="header-anchor" href="#五、经典名言精选" aria-label="Permalink to &quot;五、经典名言精选&quot;">​</a></h2><h3 id="彭子益-1" tabindex="-1">彭子益 <a class="header-anchor" href="#彭子益-1" aria-label="Permalink to &quot;彭子益&quot;">​</a></h3><blockquote><p><strong>「中气如轴，四维如轮。轴运轮行，轴滞轮停。」</strong></p></blockquote><blockquote><p><strong>「凡病皆本气自病。本气者，人身之本有之气也。」</strong></p></blockquote><blockquote><p><strong>「人身一小宇宙。宇宙的圆运动正常，则生物生；人体的圆运动正常，则人无病。」</strong></p></blockquote><blockquote><p><strong>「中医的治病，不是用药去治病，而是用药恢复人体的圆运动。」</strong></p></blockquote><blockquote><p><strong>「医道以圆运动为本，不知圆运动，不足以言医。」</strong></p></blockquote><h3 id="李可-1" tabindex="-1">李可 <a class="header-anchor" href="#李可-1" aria-label="Permalink to &quot;李可&quot;">​</a></h3><blockquote><p><strong>「阳虚之人，十之八九；阴虚之人，百不见一。」</strong>（继承黄元御）</p></blockquote><blockquote><p><strong>「凡见上热，必究其下寒。」</strong></p></blockquote><blockquote><p><strong>「中医复兴，要靠疗效说话。」</strong></p></blockquote><blockquote><p><strong>「破格用药，不是冒险，而是对病人生命负责。」</strong></p></blockquote><blockquote><p><strong>「千里马不遇伯乐，良医难逢明主。」</strong></p></blockquote><blockquote><p><strong>「彭子益先生是中医复兴之父，从此以后，中医亡不了！」</strong></p></blockquote><hr><h2 id="六、对普光师兄处方的直接指导" tabindex="-1">六、对普光师兄处方的直接指导 <a class="header-anchor" href="#六、对普光师兄处方的直接指导" aria-label="Permalink to &quot;六、对普光师兄处方的直接指导&quot;">​</a></h2><h3 id="圆运动视角下的-温潜黄芽天魂汤" tabindex="-1">圆运动视角下的&quot;温潜黄芽天魂汤&quot; <a class="header-anchor" href="#圆运动视角下的-温潜黄芽天魂汤" aria-label="Permalink to &quot;圆运动视角下的&quot;温潜黄芽天魂汤&quot;&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">圆运动环节</th><th style="text-align:left;">失常表现</th><th style="text-align:left;">对应药物</th></tr></thead><tbody><tr><td style="text-align:left;">中轴（脾胃）</td><td style="text-align:left;">中气虚寒 → 轴心不转</td><td style="text-align:left;">人参、甘草（补中气）</td></tr><tr><td style="text-align:left;">中轴湿停</td><td style="text-align:left;">干姜、茯苓（温中燥湿）</td><td style="text-align:left;"></td></tr><tr><td style="text-align:left;">左轮（肝）</td><td style="text-align:left;">肝木不升 → 血虚风动</td><td style="text-align:left;">桂枝（升肝）、当归/首乌（养肝血）</td></tr><tr><td style="text-align:left;">右轮（胆胃）</td><td style="text-align:left;">相火不降 → 上热</td><td style="text-align:left;">龙骨、牡蛎（降相火）、白芍（敛胆）</td></tr><tr><td style="text-align:left;">下焦（肾）</td><td style="text-align:left;">水寒 → 阳不归根</td><td style="text-align:left;">附子（温水）、牛膝（引火归原）</td></tr></tbody></table><p><strong>这完全符合彭子益&quot;轴转轮行&quot;的圆运动恢复原则。</strong></p><hr><h2 id="七、学习建议" tabindex="-1">七、学习建议 <a class="header-anchor" href="#七、学习建议" aria-label="Permalink to &quot;七、学习建议&quot;">​</a></h2><ol><li><strong>先读</strong>：李可主校《圆运动的古中医学》&quot;原理上篇&quot;和&quot;古方上篇&quot;</li><li><strong>再读</strong>：彭子益原文（圆运动的古中医学完整的原稿）</li><li><strong>后读</strong>：李可《急危重症疑难病经验专辑》</li><li><strong>您住在云南大理</strong>——彭子益正是云南大理人，缘分不浅</li></ol><hr><p><em>本条目为精简框架版。可扩展至彭子益医案选、李可医案选、圆运动与四圣心源的详细对比等专题。普光师兄在大理——彭子益的故乡——尤值得深入了解。</em></p>`,68)])])}const c=a(s,[["render",o]]);export{u as __pageData,c as default};
